parameters.jsCode:
const body = $json.body ?? $json

const message = String(body.message ?? '').trim()
if (!message) {
  return [
    {
      json: {
        error: 'EMPTY_MESSAGE',
        answer: 'Vui lòng nhập nội dung cần tra cứu.',
        cards: [],
        actions: [],
        meta: { intent: 'invalid', confidence: 1, calledTools: [], sources: [] },
      },
    },
  ]
}

const staffId = body.staffId ?? 'anonymous'
const facilityId = body.facilityId ?? 'default'
const sessionId = body.sessionId ?? `${staffId}-${Date.now()}`
const sessionKey = `hotel-assistant:${facilityId}:${staffId}:${sessionId}`

const today = new Intl.DateTimeFormat('en-CA', {
  timeZone: 'Asia/Ho_Chi_Minh',
  year: 'numeric',
  month: '2-digit',
  day: '2-digit',
}).format(new Date())

return [
  {
    json: {
      message,
      sessionId,
      sessionKey,
      staffId,
      facilityId,
      today,
      timezone: 'Asia/Ho_Chi_Minh',
      pageContext: body.pageContext ?? {},
      guardrails: {
        mode: 'read_only',
        allowedMethods: ['GET'],
        deniedMethods: ['POST', 'PUT', 'PATCH', 'DELETE'],
      },
    },
  },
]

const original = $('Normalize Input').first().json

function extractText(value) {
  if (typeof value === 'string') return value
  if (!value || typeof value !== 'object') return String(value ?? '')

  const direct = value.output ?? value.text ?? value.result
  if (typeof direct === 'string') return direct

  const generations = value.response?.generations ?? value.generations
  const firstGeneration = Array.isArray(generations) ? generations[0]?.[0] ?? generations[0] : undefined
  if (typeof firstGeneration?.text === 'string') return firstGeneration.text
  if (typeof firstGeneration?.message?.content === 'string') return firstGeneration.message.content

  return JSON.stringify(value)
}

function tryParseJson(value) {
  if (value && typeof value === 'object' && 'intent' in value) return value
  if (value && typeof value === 'object' && 'answer' in value) return value

  const text = extractText(value).trim()
  const fenced = text.match(/```(?:json)?\s*([\s\S]*?)```/i)
  const candidate = fenced?.[1] ?? text
  const jsonMatch = candidate.match(/\{[\s\S]*\}/)
  if (!jsonMatch) return null

  try {
    return JSON.parse(jsonMatch[0])
  } catch {
    return null
  }
}

const parsed = tryParseJson($json)

return [
  {
    json: {
      ...original,
      planner: parsed ?? {
        intent: 'unknown',
        confidence: 0,
        entities: {},
        calledTools: [],
        toolContext: {},
        warnings: ['Kh?ng parse ???c k?t qu? planner.'],
      },
    },
  },
]

